import create from 'zustand';

/**
 * @typedef {Object} EvaluationResult
 * @property {any} output - The result of the evaluation.
 * @property {boolean} success - Indicates if the evaluation was successful.
 * @property {string} [error] - The error message if the evaluation failed.
 */

/**
 * @function recursiveEvaluate
 * @param {Function} evaluateFn - The function to evaluate.
 * @param {number} maxAttempts - Maximum number of attempts for evaluation.
 * @returns {Promise<EvaluationResult>} - The result of the evaluation.
 */
export async function recursiveEvaluate(evaluateFn, maxAttempts = 5) {
    let attempt = 0;
    let result;
    while (attempt < maxAttempts) {
        try {
            const output = await evaluateFn();
            result = { output, success: true };
            return result;
        } catch (error) {
            attempt++;
            if (attempt >= maxAttempts) {
                result = { output: null, success: false, error: error.message };
            }
        }
    }
    return result;
}

/**
 * @function saveEvaluationResult
 * @param {string} key - The key for localStorage.
 * @param {EvaluationResult} result - The result to save.
 * @returns {Promise<void>}
 */
export async function saveEvaluationResult(key, result) {
    try {
        localStorage.setItem(key, JSON.stringify(result));
        await fetch('http://localhost:3001/saveResult', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({ key, result }),
        });
    } catch (error) {
        console.error('Failed to save evaluation result:', error);
    }
}

/**
 * @function loadEvaluationResult
 * @param {string} key - The key for localStorage.
 * @returns {Promise<EvaluationResult | null>}
 */
export async function loadEvaluationResult(key) {
    try {
        const cached = localStorage.getItem(key);
        if (cached) {
            return JSON.parse(cached);
        }
        const response = await fetch(`http://localhost:3001/loadResult?key=${key}`);
        if (!response.ok) throw new Error('Failed to load result from server');
        return await response.json();
    } catch (error) {
        console.error('Failed to load evaluation result:', error);
        return null;
    }
}

/**
 * @function useEvaluationStore
 * @returns {Object} - Zustand store for evaluation state.
 */
export const useEvaluationStore = create((set) => ({
    results: {},
    addResult: (key, result) => set((state) => ({
        results: { ...state.results, [key]: result }
    })),
    clearResults: () => set({ results: {} }),
}));

/**
 * @function selfCorrectingEvaluate
 * @param {Function} evaluateFn - The function to evaluate.
 * @param {string} key - Key for storing results.
 * @param {number} maxAttempts - Maximum number of attempts for evaluation.
 * @returns {Promise<void>}
 */
export async function selfCorrectingEvaluate(evaluateFn, key, maxAttempts = 5) {
    const result = await recursiveEvaluate(evaluateFn, maxAttempts);
    await saveEvaluationResult(key, result);
    useEvaluationStore.getState().addResult(key, result);
}